  // 8. 바인딩과 범위
  // ========================================

  println("--- 8. 바인딩과 범위 ---");
  let p1 = categorize_priority(2);
  let p2 = categorize_priority(5);
  let p3 = categorize_priority(8);
  let p4 = categorize_priority(15);
