  // 10. 시스템 이벤트 처리
  // ========================================

  println("--- 10. 시스템 이벤트 처리 ---");
  let evt1 = handle_system_event("Startup", "v5.4");
  let evt2 = handle_system_event("Error", "권한 부족");
  let evt3 = handle_system_event("Shutdown", "유지보수");
  let evt4 = handle_system_event("Update", "important");
  let evt5 = handle_system_event("Update", "minor");
  println(evt1);
  println(evt2);
  println(evt3);
  println(evt4);
  println(evt5);
  println("");

  // ========================================
  // v5.4의 의의
  // ========================================

  println("=== v5.4의 의의 ===");
  println("");
  println("[안전성]");
  println("모든 경우를 처리하도록 강제하는 패턴 매칭");
  println("");

  println("[명확성]");
  println("데이터 구조에 의도가 드러나고 코드의 흐름이 직관적");
  println("");

  println("[유지보수성]");
  println("새로운 경우 추가 시 컴파일러가 알려줌");
  println("");

  println("[우아함]");
  println("복잡한 if-else 문을 간결한 match로 표현");
  println("");

  // 최종 메시지
  println("=== v5.4 완성 ===");
  println("");
  println("좋은 러스트 설계자는 로직을 길게 코딩하기보다,");
  println("데이터 구조(Enum)를 정교하게 짜서");
  println("match 구문이 자연스럽게 흐르도록 유도합니다.");
  println("");
  println("이것이 바로 '데이터 지향 설계'의 정수입니다.");
  println("");
  println("저장 필수 너는 기록이 증명이다 gogs");
}

